        __m512d s2r=_mm512_add_pd(x2_re,x3_re), s2i=_mm512_add_pd(x2_im,x3_im);
        __m512d d1r=_mm512_sub_pd(x1_re,x4_re), d1i=_mm512_sub_pd(x1_im,x4_im);
        __m512d d2r=_mm512_sub_pd(x2_re,x3_re), d2i=_mm512_sub_pd(x2_im,x3_im);
        __m512d ss_r=_mm512_add_pd(s1r,s2r), ss_i=_mm512_add_pd(s1i,s2i);
        __m512d t0r=_mm512_fnmadd_pd(cD,ss_r,x0_re), t0i=_mm512_fnmadd_pd(cD,ss_i,x0_im);
        x0_re=_mm512_add_pd(x0_re,ss_r); x0_im=_mm512_add_pd(x0_im,ss_i);
