        ST(&out_im[0*os+k], x0_im);
        ST(&out_re[1*os+k], x1_re);
        ST(&out_im[1*os+k], x1_im);
        ST(&out_re[2*os+k], x2_re);
        ST(&out_im[2*os+k], x2_im);
        ST(&out_re[3*os+k], x3_re);
